mapper.select:
select id, title, summary, location, poster_url, start_time, end_time, max_participants, status
from campus_activity
where id = #{id}

mapper.insert:
insert into campus_activity_registration (
    activity_id, user_id, real_name, student_no, phone, status, registered_at
)
values (
    #{activityId}, #{userId}, #{realName}, #{studentNo}, #{phone}, #{status}, #{registeredAt}
)

mapper.update:
update campus_activity_registration
set real_name = #{realName},
    student_no = #{studentNo},
    phone = #{phone},
    status = #{status}
where id = #{id}

update campus_activity_registration
set status = 'CANCELLED'
where activity_id = #{activityId} and user_id = #{userId}
